try:
        # Step 1: Create or recreate application
        app_uid = "test-app-pagination"
        log(f"Creating application with UID: {app_uid}")

        try:
            # Try to create the application
            app = svix.application.create(ApplicationIn(
                name="Test App",
                uid=app_uid
            ))
            log(f"Created application: {app.id}")
        except Exception as e:
            # If application already exists, delete and recreate
            if "already exists" in str(e).lower() or "conflict" in str(e).lower():
                log(f"Application {app_uid} already exists, deleting and recreating...")
                try:
                    # List applications to find the existing one
                    apps = svix.application.list()
                    for existing_app in apps.data:
                        if existing_app.uid == app_uid:
                            svix.application.delete(existing_app.id)
                            log(f"Deleted existing application: {existing_app.id}")
                            break

                    # Recreate the application
                    app = svix.application.create(ApplicationIn(
                        name="Test App",
                        uid=app_uid
                    ))
                    log(f"Recreated application: {app.id}")
                except Exception as delete_error:
                    log(f"Error handling existing application: {delete_error}")
                    raise
            else:
                log(f"Error creating application: {e}")
                raise

